SELECT analysis_id, user_id, business_type, business_id, dify_workflow_id, request_payload, response_text, status, error_message, created_time FROM ai_analysis_record WHERE 1 = 1
AND user_id = #{userId}
AND business_type = #{businessType}
ORDER BY created_time DESC, analysis_id DESC

SELECT analysis_id, user_id, business_type, business_id, dify_workflow_id, request_payload, response_text, status, error_message, created_time FROM ai_analysis_record WHERE status = 'SUCCESS' AND response_text IS NOT NULL AND response_text != '' AND business_type = #{businessType} AND business_id = #{businessId}
AND user_id = #{userId}
AND user_id IS NULL
ORDER BY created_time DESC, analysis_id DESC LIMIT 1
